import React, { useState, useEffect, useRef } from "https://esm.sh/react";
import { createRoot } from "https://esm.sh/react-dom/client";
import Chart from "https://esm.sh/chart.js/auto";

const Sidebar = ({ show }) => {
  return (
    <div className={`sidebar bg-white p-3 h-100 ${show ? "show" : ""}`}>
      <ul className="list-group sidebar-nav">
        <li className="list-group-item">
          <button className="btn active">Dashboard</button>
        </li>
        <li className="list-group-item">
          <button className="btn">Analytics</button>
        </li>
        <li className="list-group-item">
          <button className="btn">Reports</button>
        </li>
        <li className="list-group-item">
          <button className="btn">Settings</button>
        </li>
      </ul>
    </div>
  );
};

const Dashboard = () => {
  const chartRef = useRef(null);

  useEffect(() => {
    const ctx = chartRef.current.getContext("2d");
    const myChart = new Chart(ctx, {
      type: "bar",
      data: {
        labels: ["January", "February", "March", "April", "May", "June", "July"],
        datasets: [
          {
            label: "This Year",
            data: [12200, 12000, 8000, 18970, 11000, 14500, 9300],
            backgroundColor: "#F2865E",
            borderRadius: 20,
          },
          {
            label: "Last Year",
            data: [9500, 11500, 7500, 16900, 4500, 11410, 8500],
            backgroundColor: "#F2C1AE",
            borderRadius: 20,
          },
        ],
      },
      options: {
        responsive: true,
        maintainAspectRatio: false,
      },
    });
    return () => {
      myChart.destroy();
    };
  }, []);

  return (
    <div className="dashboard-container d-flex">
      <Sidebar show={true} />
      <div className="content p-3">
        <h1 className="h3 mb-3">Dashboard</h1>
        <div className="card">
          <div className="card-body">
            <h5 className="card-title">Statistics</h5>
            <canvas ref={chartRef}></canvas>
          </div>
        </div>
      </div>
    </div>
  );
};

const App = () => {
  return <Dashboard />;
};

const root = createRoot(document.getElementById("root"));
root.render(<App />);
